  <!-- ===== HERO ===== -->
  <section class="hero">
    <div class="hero-bg"></div>
    <div class="hero-grid-lines"></div>
    <div class="float-el"></div>
    <div class="float-el"></div>
    <div class="float-el"></div>

    <div class="hero-content">
      <div class="hero-tag"><?= __('hero.tag') ?></div>
      <div style="margin-bottom: 20px;">
        <img
          src="data:image/png;base64,"
          alt="Q'SAMBA — Alegria e Folia"
          style="height: clamp(80px, 12vw, 160px); width: auto; filter: drop-shadow(0 4px 24px rgba(255,226,52,0.4)); animation: fadeUp 1s ease 0.2s both; mix-blend-mode: screen;">
      </div>
      <p class="hero-subtitle">
        <em><?= __('hero.subtitle_1') ?></em><br>
        <?= __('hero.subtitle_2') ?><br>
        <span style="color:rgba(255,248,236,0.5);font-weight:400"><?= __('hero.subtitle_3') ?></span>
      </p>
      <div class="hero-btns">
        <a href="#bilhetes" class="btn-primary">
          <span><?= __('hero.btn_tickets') ?></span>
        </a>
        <a href="#eventos" class="btn-secondary">
          <span><?= __('hero.btn_events') ?></span>
        </a>
      </div>
    </div>

    <div class="hero-sil"
      style="width:110px;left:calc(44% - 40px);top:20%;z-index:2;--sb:rotate(-12deg);animation:silF 10s ease-in-out 0s infinite;">
      <img
        src="data:image/png;base64,"
        style="opacity:0.3">
    </div>
    <div class="hero-sil"
      style="width:56px;left:calc(48% - 20px);top:62%;z-index:2;--sb:rotate(15deg);animation:silS 9s ease-in-out 1.5s infinite;">
      <img
        src="data:image/png;base64,"
        style="opacity:0.3">
    </div>

    <!-- Collage Images -->
    <div class="hero-collage">
      <div class="collage-img c1">
        <img
          src="data:image/jpeg;base64,"
          alt="Q'SAMBA Live">
      </div>
      <div class="collage-img c2">
        <img
          src="data:image/jpeg;base64,"
          alt="Q'SAMBA ao vivo">
      </div>
      <div class="collage-img c3">
        <img
          src="data:image/jpeg;base64,"
          alt="Q'SAMBA Festival">
      </div>
      <div class="collage-img c4">
        <img
          src="data:image/jpeg;base64,"
          alt="Q'SAMBA artista">
      </div>
    </div>

    <div class="deco"
      style="width:100px;bottom:-20px;left:-5px;--db:rotate(12deg);animation:ds 9s ease-in-out 1s infinite;"><img
        src="data:image/png;base64,"
        style="opacity:0.5"></div>
    <div class="deco"
      style="width:120px;bottom:-90px;right:-5px;--db:rotate(15deg);animation:df 10s ease-in-out 0s infinite;"><img
        src="data:image/png;base64,"
        style="opacity:0.5"></div>
    <div class="hero-scroll-hint">
      <span class="scroll-text"><?= __('hero.scroll') ?></span>
      <div class="scroll-line"></div>
    </div>
  </section>

